from flask import Flask, request
import hmac
import hashlib
import os

app = Flask(__name__)
webhook_secret = os.environ['WEBHOOK_SECRET'] # get secret from environment variables

@app.route('/webhook', methods=['POST'])
def webhook():
    signature = request.headers.get('X-HubSpot-Signature')
    
    if not validate_signature(signature, request.data):
        return 'Invalid Signature', 403
        
    data = request.get_json() # assume the payload is json

    process_webhook_event(data)
    
    return '', 200

def validate_signature(signature, data):
    hash = hmac.new(
        webhook_secret.encode(),
        msg=data,
        digestmod=hashlib.sha256
    ).hexdigest()

    return hmac.compare_digest("sha256=" + hash, signature)

def process_webhook_event(data):
    # implement your business logic here
    print('Webhook event received:', data) 

if __name__ == '__main__':
    app.run()